const body = $('Inbound SMS Webhook').first().json.body;

// Contact ID — accept both snake_case (contact_id) and camelCase (contactId) from GHL
const contactId = body?.contact_id || body?.contactId || body?.customData?.Type_contact_id || null;
if (!contactId || contactId === 'unknown') {
  throw new Error('INVALID_PAYLOAD: Missing or invalid contact_id');
}

// MESSAGE BODY — GHL sends the current event body as 'debug_message_body' ([message.body]).
// That field is EMPTY for missed calls (no SMS body on a call event) and populated for SMS.
// 'Message_Body' ([contact.last_inbound_message]) is NOT used here — it holds the last
// received message and would be non-empty even for missed calls, breaking detection.
// Test payloads use nested message.body or flat body — kept as fallbacks.
const rawBody = body?.message?.body
             || body?.debug_message_body
             || body?.body
             || '';

const messageType = body?.message?.type ?? body?.type ?? null;
const msgText = (typeof rawBody === 'string' ? rawBody : String(rawBody || '')).trim();
const isMissedCall = !msgText || msgText === '';

if (!isMissedCall) {
  const invalid = ['undefined', 'null', 'none', 'test'];
  if (invalid.includes(msgText.toLowerCase())) {
    throw new Error('INVALID_PAYLOAD: Invalid message body value: ' + msgText);
  }
}

return {
  json: {
    contact_id: contactId,
    is_missed_call: isMissedCall,
    message_body: msgText,
    message_type: messageType,
    validated: true
  }
};

const webhookBody=$('Inbound SMS Webhook').first().json.body;
const contactId=$('Validate Payload').first().json.contact_id;
if(!contactId)throw new Error('No contact ID in missed call payload');
const firstName=webhookBody.user?.firstName||'Ryan';
const now=new Date();
const dateLabel=`${String(now.getMonth()+1).padStart(2,'0')}/${String(now.getDate()).padStart(2,'0')}/${now.getFullYear()}`;
const timeLabel=`${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')} UTC`;
return{json:{contact_id:contactId,first_name:firstName,missed_call_note:`[MISSED CALL - ${dateLabel} ${timeLabel}] Seller called in.`,auto_text:`Hey, this is ${firstName}, sorry I missed your call. I'm with someone right now, but didn't want to leave you hanging. What's up?`,pipeline_id:'CKmxatJBFjuM8NS4p5D6',stage_id:'4cfbee5e-b045-4aba-b33a-3a41632eb288'}};

