const contactId = $('Handle Missed Call').first().json.contact_id;
const firstName = $('Handle Missed Call').first().json.first_name;
const cooldownMinutes = 30;
const now = new Date();
const cooldownMs = cooldownMinutes * 60 * 1000;
const since30min = new Date(now - cooldownMs);

// Fetch Missed Call Queue is an HTTP Request node — Supabase returns a JSON array
// as a single n8n item where item.json IS the array. Flatten it.
const allItems = $('Fetch Missed Call Queue').all();
const rawJson = allItems.map(item => item.json);
const allMissedCalls = rawJson.flatMap(j => Array.isArray(j) ? j : [j]).filter(Boolean);

// Calls within the 30-min window (includes current execution)
const recentMissed = allMissedCalls.filter(e => new Date(e.received_at) >= since30min);
const should_send = recentMissed.length <= 1;

// Previous calls before the window - for text selection
const previousMissed = allMissedCalls
  .filter(e => new Date(e.received_at) < since30min)
  .sort((a, b) => new Date(b.received_at) - new Date(a.received_at));
const lastCallTime = previousMissed.length > 0 ? new Date(previousMissed[0].received_at) : null;

const easternNow = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }));
const easternMidnight = new Date(easternNow);
easternMidnight.setHours(0, 0, 0, 0);
const lastCallEastern = lastCallTime
  ? new Date(lastCallTime.toLocaleString('en-US', { timeZone: 'America/New_York' }))
  : null;

const noPriorCalls = !lastCallTime;
const calledEarlierToday = lastCallEastern && lastCallEastern >= easternMidnight;

let auto_text;
if (noPriorCalls) {
  auto_text = `Hey, this is ${firstName}, sorry I missed your call. I'm with someone right now, but didn't want to leave you hanging. What's up?`;
} else if (calledEarlierToday) {
  auto_text = `Hey, keep missing each other. Shoot me a text with a good time and I'll call you then.`;
} else {
  auto_text = `Hey, saw I missed your call again. Didn't want to leave you hanging. What's going on?`;
}

return {
  json: {
    contact_id: contactId,
    total_in_db: allMissedCalls.length,
    recent_missed_calls: recentMissed.length,
    should_send,
    auto_text,
    cooldown_minutes: cooldownMinutes
  }
};

// Post-processing — handles tool_use (structured) and text (legacy) responses
const item = JSON.parse(JSON.stringify($input.first().json));
const content = item?.content || [];

// Find tool_use block if present (from forced tool_choice)
const toolUse = content.find(c => c.type === 'tool_use');

if (toolUse && toolUse.input) {
  let response = toolUse.input.response || '';
  response = response.replace(/\u2014/g, ', ').replace(/\u2013/g, '-');
  response = response.replace(/[\u{1F300}-\u{1FAFF}\u{2600}-\u{27BF}\u{1F000}-\u{1F02F}\u{1F0A0}-\u{1F0FF}\u{1F100}-\u{1F1FF}\u{1F200}-\u{1F2FF}\u{1F900}-\u{1F9FF}\u{1FA00}-\u{1FA6F}]/gu, '');
  response = response.replace(/ - /g, ', ');
  response = response.replace(/!/g, '.');
  response = response.replace(/,\s*,/g, ',').replace(/\.\s*\./g, '.').replace(/\s{2,}/g, ' ').trim();
  // Price leak filter — MUST run before serialization
  const priceLeakPattern = /\$\d[\d,]*k?\s*(in the ballpark|in range|sound right|what you|close to|around what|were hoping)/i;
  if (priceLeakPattern.test(response)) {
    response = response.replace(/\$\d[\d,]*k?[^.?!]*(in the ballpark|in range|sound right|what you|close to|around what|were hoping)[^.?]*/gi, 'What number would actually make it worth your time');
  }
  const output = { response: response, conversation_ended: toolUse.input.conversation_ended === true, price_confirmed: toolUse.input.price_confirmed === true };
  item.content = [{ type: 'text', text: JSON.stringify(output) }];
  return { json: item };
}

// Legacy fallback: text response
const raw = $input.first().json?.content?.[0]?.text || $input.first().json?.text || '';
if (!raw) return { json: $input.first().json };
let cleaned = raw;
cleaned = cleaned.replace(/\u2014/g, ', ').replace(/\u2013/g, '-');
cleaned = cleaned.replace(/[\u{1F300}-\u{1FAFF}\u{2600}-\u{27BF}\u{1F000}-\u{1F02F}\u{1F0A0}-\u{1F0FF}\u{1F100}-\u{1F1FF}\u{1F200}-\u{1F2FF}\u{1F900}-\u{1F9FF}\u{1FA00}-\u{1FA6F}]/gu, '');
cleaned = cleaned.replace(/ - /g, ', ');
cleaned = cleaned.replace(/!/g, '.');
cleaned = cleaned.replace(/,\s*,/g, ',').replace(/\.\s*\./g, '.').replace(/\s{2,}/g, ' ').trim();
if (item?.content?.[0]?.text) {
  item.content[0].text = cleaned;
} else if (item?.text) {
  item.text = cleaned;
}
return { json: item };

const combinedMsg = $('Process Queue').first().json.combined_message || '';
const webhookBody = $('Inbound SMS Webhook').first().json.body;
const contactId = $('Process Queue').first().json.contact_id;

// AI/Bot disclosure patterns - catches attacks/accusations, not seller questions
// Intentional gap: "are you a real person", "is this automated text", "am I talking to a human"
// are legitimate seller questions handled by PATTERN 3. Only catch declarative accusations
// and demands for AI disclosure, not simple identity curiosity.
const aiPatterns = [
  // "are you a bot/ai/robot/computer/machine/chatbot" - catches bot accusations but NOT "automated"
  // "automated" alone is excluded here because "is this an automated text" is a seller question, not an attack
  /\b(?:are you|is this)\s+(?:a\s+)?(?:bot|ai|robot|computer|machine|chatbot|artificial intelligence)/i,
  // "am I talking to a bot/ai/robot/computer/machine" - removed "real person/human" which catches normal seller questions
  /\b(?:am i|i'?m)\s+(?:talking|speaking|texting|chatting)\s+(?:to|with)\s+(?:a\s+)?(?:bot|ai|robot|computer|machine)/i,
  // "is this a program/software/an AI" - kept, these are clearly bot-check framing not normal questions
  /\bis this\s+(?:a program|software|an? ai|an? artificial)/i,
  // "prove you're human/not a bot" - accusation/demand framing
  /\bprove\s+(?:you'?re|you are|ur)\s+(?:human|real|a person|not a bot)/i,
  // Declarative accusations with certainty language
  /\b(?:this is|you'?re|you are|ur)\s+(?:definitely|obviously|clearly|probably|just)?\s*(?:a\s+)?(?:bot|ai|robot|automated|computer|chatbot)/i,
  /\bknow\s+(?:this is|you'?re|you are)\s+(?:a\s+)?(?:bot|ai|automated|robot)/i,
  /\b(?:definitely|obviously|clearly)\s+(?:a\s+)?(?:bot|ai|robot|automated)/i,
  /\bbot\s+(?:lol|lmao|haha|right|confirmed|detected)/i,
];

// Prompt injection patterns
const injectionPatterns = [
  /ignore\s+(?:all\s+)?(?:previous|prior|above)\s+instructions?/i,
  /you\s+are\s+now/i,
  /new\s+instructions?:/i,
  /system\s+(?:prompt|override)/i,
  /forget\s+(?:everything|all|your\s+instructions?)/i,
  /act\s+as\s+(?:if\s+)?you\s+(?:are|were)/i,
  /pretend\s+(?:you\s+)?(?:are|to\s+be)/i,
  /disregard\s+(?:your|all|previous)/i,
  /reveal\s+(?:your\s+)?(?:prompt|instructions)/i,
  /\bjailbreak/i,
  /\bdeveloper\s+mode/i,
  /bypass\s+(?:your|all|safety)/i,
  /from\s+now\s+on,?\s+you/i,
  /as\s+of\s+now\s+you/i,
  /new\s+role:/i,
  /override\s+your/i,
  /your\s+new\s+(?:instructions?|role)/i,
  /stop\s+being/i,
  /you\s+must\s+now/i,
  /\bDAN\s+mode/i,
];

// Commercial intent signals — if seller is ALSO engaging commercially,
// suppress ai_disclosure detection and let Claude handle naturally.
// Prevents false positives like: "Lol definitely a robot. Whatever, how much you paying?"
const commercialIntentPatterns = [
  /\b(?:how much|what.*(?:offer|pay|worth|price)|sell|selling|buy|buying|interested|acres?|lot|property|land|parcel)\b/i,
  /\$\s*\d/,
  /\b\d+[kK]\b/,
  /\b(?:call me|let'?s talk|set up a time|schedule)\b/i,
];

const isAiDisclosure = aiPatterns.some(p => p.test(combinedMsg));
const isPromptInjection = injectionPatterns.some(p => p.test(combinedMsg));
const hasCommercialIntent = commercialIntentPatterns.some(p => p.test(combinedMsg));

// KEY LOGIC: If seller accuses bot BUT also shows commercial intent,
// let Claude handle it — they're engaging past the accusation.
// Prompt injections are NEVER suppressed regardless of commercial intent.
const effectiveAiDisclosure = isAiDisclosure && !hasCommercialIntent;
const isInjection = effectiveAiDisclosure || isPromptInjection;

return {
  json: {
    is_injection: isInjection,
    injection_type: effectiveAiDisclosure ? 'ai_disclosure' : (isPromptInjection ? 'prompt_injection' : null),
    contact_id: contactId,
    combined_message: combinedMsg,
    webhook_body: webhookBody
  }
};

const detect = $('Detect Injection').first().json;
const wb = detect.webhook_body;
const contactId = detect.contact_id;
const injectionType = detect.injection_type;

// Get existing history from Supabase
let existingHistory = [];
let existingRow = {};
try {
  const histResult = $('Get Injection History').first().json;
  const row = Array.isArray(histResult) ? histResult[0] : histResult;
  if (row && row.conversation_history) {
    existingRow = row;
    const raw = row.conversation_history;
    existingHistory = typeof raw === 'string' ? JSON.parse(raw) : raw;
  }
} catch(e) { existingHistory = []; }

// Property context
const address = wb['Street Address'] || wb.address || wb.customData?.['Street Address'] || '';
const city = wb.city || wb.customData?.city || '';
const state = wb.State || wb.state || wb.customData?.State || '';
const county = wb.county || wb.customData?.county || '';
const streetName = address ? address.replace(/^\d+\s*/, '').trim() : '';
const locationLabel = city || county || state || 'the area';
const propertyRef = streetName ? streetName + ' property' : (city ? city + ' property' : locationLabel + ' parcel');

const phone = wb.phone || wb.customData?.phone || '';

// Hardcoded deflections - never confirm or deny AI
const aiDeflections = [
  `You think I'm AI? I wish, it sure would make my life a lot easier. What's going on with the ${locationLabel} property?`,
  `AI? Man I wish I was that smart. I hope I wasn't cold calling about land if I was AI. Would you be open to chatting about the ${propertyRef}?`,
  `Ha if I was AI I probably wouldn't be texting about land on a ${['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][new Date().getDay()]}. What's the story with the ${locationLabel} parcel?`,
];

const promptDeflections = [
  `Think you sent that to the wrong number. I was texting about the ${locationLabel} parcel.`,
  `Ha what? Anyway I was reaching out about the ${propertyRef}, you open to talking about it?`,
  `Wrong thread maybe? I texted about your property in ${locationLabel}.`,
];

const responses = injectionType === 'ai_disclosure' ? aiDeflections : promptDeflections;
const response = responses[Math.floor(Math.random() * responses.length)];

// Character stripping (same logic as production)
let cleaned = response;
cleaned = cleaned.replace(/\u2014/g, ', ').replace(/\u2013/g, '-');
cleaned = cleaned.replace(/[\u{1F300}-\u{1FAFF}\u{2600}-\u{27BF}\u{1F000}-\u{1F02F}\u{1F0A0}-\u{1F0FF}\u{1F100}-\u{1F1FF}\u{1F200}-\u{1F2FF}\u{1F900}-\u{1F9FF}\u{1FA00}-\u{1FA6F}]/gu, '');
cleaned = cleaned.replace(/!/g, '.');
cleaned = cleaned.replace(/,\s*,/g, ',').replace(/\.\s*\./g, '.').replace(/\s{2,}/g, ' ').trim();

// Build updated conversation history
const sellerMsg = detect.combined_message;
const updatedHistory = [
  ...existingHistory,
  { role: 'user', content: sellerMsg },
  { role: 'assistant', content: cleaned }
];

const totalTurns = (existingRow.total_turns || 0) + 1;
const currentStatus = existingRow.lead_status || 'ACTIVE';

return {
  json: {
    contact_id: contactId,
    phone: phone,
    sms_response: cleaned,
    injection_type: injectionType,
    conversation_history: updatedHistory,
    total_turns: totalTurns,
    lead_status: currentStatus,
    first_name: wb.user?.firstName || wb.customData?.owner_first_name || '',
    last_name: wb.user?.lastName || wb.customData?.owner_last_name || ''
  }
};

