const pr = $('Process and Route').first().json;
const sellerMsg = $('Process Queue').first().json.combined_message || '';
const draftSms = pr.sms_response;
const contactId = pr.contact_id;

// Get prior AI replies from conversation history if available
// Process and Route outputs conversation_history as a stringified JSON array
let priorReplies = [];
try {
  const histRaw = pr.conversation_history;
  const hist = typeof histRaw === 'string' ? JSON.parse(histRaw) : (histRaw || []);
  priorReplies = hist
    .filter(h => h.role === 'assistant' && h.content && !h.content.startsWith('[REASONING]'))
    .map(h => h.content)
    .slice(-3);
} catch(e) {}

const hasPriorReplies = priorReplies.length > 0;
const brokenRecordCheck = hasPriorReplies
  ? `3. BROKEN RECORD: Here are the last few replies Ryan has sent in this conversation:\n${priorReplies.map((r,i) => `Prior reply ${i+1}: ${r}`).join('\n')}\nIf the draft ends with the SAME type of question as the most recent prior reply (both end with a price ask like "number in mind", both end with "open to a conversation"), change the close to a different type. Do NOT flag this check if there are no prior replies, or if the current draft's close is different from the prior close.`
  : `3. BROKEN RECORD: Not applicable — this is the first reply in the conversation. Do not flag repetition on turn 1. A price-ask close like "do you have a number in mind" is appropriate on turn 1 and should be preserved.`;

const reviewPrompt = `You are a quality reviewer for SMS messages sent by a land buyer named Ryan. Your default behavior is to return the draft UNCHANGED. Only rewrite if you can identify a specific, concrete problem from the checks below. A good draft with a minor stylistic difference from your preference should be returned unchanged. Preserving Ryan's voice and structure matters more than polishing. Only rewrite when a check is actually triggered, and when you do rewrite, make the SMALLEST change that fixes the problem. Do not delete closing questions unless they are specifically flagged by a check below.

CHECKS:
1. STREET NAME IN CLOSE: If the last sentence contains a street name, address, city name, or property reference (like "Gray Rd parcel" or "Eatonton property"), remove just that reference. The close should use "it" or nothing. Example fix: "Do you have a number in mind for the Gray Rd parcel?" → "Do you have a number in mind?" Keep the question itself.
2. FILLER OPENERS: If the response starts with: Great, Absolutely, Of course, Certainly, Sure thing, Happy to help, Thanks for reaching out, I appreciate that, Sounds good, Fair question, Fair point, Good question, That's a fair, That's a good, Honestly, Honest answer, Frankly — rewrite just the opener, keep everything else.
${brokenRecordCheck}
4. EXCLAMATION POINTS: Remove any ! characters (replace with . or nothing).
5. EMOJI: Remove any emoji.
6. LENGTH: The draft should be 1-3 sentences for most cases, but longer is fine when the seller's message earned it. Only tighten if clearly bloated (5+ sentences of redundant content).
7. VOCABULARY: Flag and replace any of these words: comps, circle back, touch base, motivated seller, cash offer, raw land, financing contingencies.

SELLER MESSAGE: ${sellerMsg}

DRAFT SMS TO REVIEW:
${draftSms}

Respond with ONLY the final SMS text to send. No explanation, no preamble, no quotes. Just the message. If no check is triggered, return the draft exactly as given.`;

return {
  json: {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 400,
    messages: [{ role: 'user', content: reviewPrompt }],
    contact_id: contactId,
    original_sms: draftSms,
    process_route_data: pr
  }
};

const reviewInput = $('Build Review Request').first().json;
const httpResponse = $input.first().json;
const originalData = reviewInput.process_route_data;

let reviewedSms = reviewInput.original_sms; // fallback to original

try {
  if (httpResponse.content && httpResponse.content[0] && httpResponse.content[0].text) {
    const reviewed = httpResponse.content[0].text.trim();
    // Basic sanity: reviewed response should be non-empty and not too long
    if (reviewed.length > 5 && reviewed.length < 1000) {
      reviewedSms = reviewed;
    }
  }
} catch(e) {
  // If review call failed, use original — don't block the SMS
}

// Pass through all Process and Route data, replacing sms_response
return {
  json: {
    ...originalData,
    sms_response: reviewedSms,
    original_sms: reviewInput.original_sms,
    was_rewritten: reviewedSms !== reviewInput.original_sms
  }
};

// === BUILD CLAUDE REQUEST v2 ===
// Assembly prefix (lines 1-246) preserved from v1. Only prompt text changed.
// Replaces: Build Claude Request (node id: efeecfad-4886-4de6-84c9-5c2b083050e6)
// ===

const webhookBody = $('Inbound SMS Webhook').first().json.body;
const combinedMsg = $('Process Queue').first().json.combined_message || webhookBody.message?.body || webhookBody.debug_message_body || webhookBody.message || '';
const supabaseRow = $('Merge Context').first().json.supabase_row || {};
const busyBlocks = $('Merge Context').first().json.busy_blocks || [];
const ghlOutboundMessages = $('Merge Context').first().json.ghl_outbound_messages || [];
const isNewContact = !supabaseRow.id;
const totalTurns = supabaseRow.total_turns || 0;

// Property data from webhook
const property = {
  apn: webhookBody.APN || 'unknown',
  address: webhookBody['Street Address'] || 'unknown',
  city: webhookBody.city || 'unknown',
  state: webhookBody.State || 'unknown',
  acres: webhookBody.acres || 'unknown',
  county: webhookBody.county || 'unknown',
  zoning: webhookBody.zoning || 'unknown',
  subdivision: webhookBody.subdivision || 'none on file',
  latitude: webhookBody.latitude || 'unknown',
  longitude: webhookBody.longitude || 'unknown',
  owner_legal: webhookBody.owner_legal || 'unknown',
  secondary_name: webhookBody.secondary_name || 'none on file',
  owner_type: webhookBody.owner_type || 'unknown',
  assd_val: webhookBody.assd_val || 'unknown',
  taxes_yr: webhookBody.taxes_yr || 'unknown',
  last_sold_date: webhookBody.last_sold_date || 'unknown',
  last_sale_amount: webhookBody.last_sale_amount || 'unknown',
  listing_type: webhookBody.listing_type || 'not listed',
  listing_price: webhookBody.listing_price || 'not listed',
  property_url: webhookBody.property_url || 'unknown',
  purchase_date: webhookBody.purchase_date || 'unknown',
  purchase_amount: webhookBody.purchase_amount || 'unknown',
  mail_address: webhookBody.mail_address || 'unknown',
  mail_city: webhookBody.mail_city || 'unknown',
  mail_state: webhookBody.mail_state || 'unknown',
  mail_zip: webhookBody.mail_zip || 'unknown',
  improvements: webhookBody.improvements || webhookBody.property_improvements || '',
  utilities: webhookBody.utilities || webhookBody.property_utilities || '',
  last_seller_reply: webhookBody.last_seller_reply || 'unknown',
  last_ai_reply: webhookBody.last_ai_reply || 'unknown',
  outreach_attempt: webhookBody.outreach_attempt || 'unknown'
};

